parameters.jsCode:
const candidate = $input.first().json;
const parsed_resume = typeof candidate.parsed_resume === 'string'
  ? JSON.parse(candidate.parsed_resume)
  : candidate.parsed_resume;

const flags = [];

// No work experience
if (!parsed_resume.work_experience || parsed_resume.work_experience.length === 0) {
  flags.push('No work experience listed');
}

// No years experience
if (!parsed_resume.years_experience) {
  flags.push('Years of experience could not be determined');
}

// Short tenure check
if (parsed_resume.work_experience && parsed_resume.work_experience.length >= 2) {
  const shortRoles = parsed_resume.work_experience.filter(w => {
    if (!w.start_date || !w.end_date || w.end_date === 'current') return false;
    const start = new Date(w.start_date);
    const end   = new Date(w.end_date);
    const months = (end - start) / (1000*60*60*24*30);
    return months < 6;
  });
  if (shortRoles.length >= 2) flags.push('Multiple short tenure roles detected');
}

return [{
  json: {
    candidate_id:      $('Webhook').first().json.body.candidate_id,
    application_id:    $('Webhook').first().json.body.application_id,
    job_id:            $('Webhook').first().json.body.job_id,
    score:             $('Webhook').first().json.body.score,
    recommendation:    $('Webhook').first().json.body.recommendation,
    new_status:        $('Webhook').first().json.body.new_status,
    notify_type:       $('Webhook').first().json.body.notify_type,
    recruiter_summary: $('Webhook').first().json.body.recruiter_summary,
    interview_questions: $('Webhook').first().json.body.interview_questions,
    candidate_name:    parsed_resume.full_name,
    years_experience:  parsed_resume.years_experience,
    recent_title:      parsed_resume.work_experience?.[0]?.title || 'N/A',
    recent_company:    parsed_resume.work_experience?.[0]?.company || 'N/A',
    top_skills:        parsed_resume.skills?.slice(0, 5) || [],
    risk_flags:        flags,
  }
}];

